mapper.insert:

    SELECT MCP_EVENT_PROMOTION_SEQ.NEXTVAL FROM DUAL

INSERT INTO MCP_EVENT_PROMOTION (
    EVENT_PROMOTION_ID
    ,EVENT_CODE
    ,NAME
    ,PHONE
    ,AGREE
    ,BIRTH_DATE
    ,CI
    ,DI
    ,USE_TEL_CODE
    ,USE_PAY_AMT
    ,SYS_RDT
    ,SYS_RDATE
    ,SEL1
    ,SEL2
    ,SEL3
) VALUES (
    #{eventPromotionId}
    ,#{code}
    ,#{name}
    ,#{phone}
    ,#{agree}
    ,#{birthDate}
    ,#{ci}
    ,#{di}
    ,#{useTelCode}
    ,#{usePayAmt}
    ,TO_CHAR(SYSDATE,'YYYYMMDD')
    ,SYSDATE
    ,#{sel1}
    ,#{sel2}
    ,#{sel3}
)
